import json
import pandas as pd

def load_records(x):
    if isinstance(x, str) and x.endswith('.json'):
        with open(x, 'r', encoding='utf-8') as f:
            return json.load(f)
    return x

cit = load_records(var_call_6S3fWynTViCcSU89pTWYLcsU)
chi_files = var_call_gzJ24rJa0EVzaBEoJMILKTjE
chi_titles = {d['filename'][:-4] for d in chi_files}

cit_df = pd.DataFrame(cit)
cit_df['citation_count'] = pd.to_numeric(cit_df['citation_count'], errors='coerce').fillna(0).astype(int)
chi_cit = cit_df[cit_df['title'].isin(chi_titles)]

total = int(chi_cit['citation_count'].sum())
res = {
    'total_citation_count': total,
    'num_papers': int(chi_cit['title'].nunique())
}
print('__RESULT__:')
print(json.dumps(res))

